clear(); close all;
%[text] ## Parameters
% parameters
numUsr = 1;
numSym = 128;
samRate = 122.88e6;
symRate = 3.84e6;
osf = samRate / symRate;
carrierFreq = 1e9;
wavelen = 299792458 / carrierFreq;

elemSpace = wavelen / 2;  % half-wavelength spacing
numElem = [4 4];          % number of array elements
snr_db = 10;              % signal-to-noise ratio in dB
pwrSource = 1;            % source signal power
pwrNoise = pwrSource / (10^(snr_db / 10)); % noise power from SNR
E = referenceEllipsoid('sphere');

usrLla = [[37.78, 36.59, 0]',[37.58, 37.51, 0]'];
usrLla = usrLla(:,1:numUsr);
data = [2026, 03, 12, 08, 53, 0];
utc = datetime(data);
tle = tleread("./tle/starlink_20260312.tle");
arrUpa = createUpa(numElem, elemSpace);


% satellite scene
scene = genMultiSatScene(utc, tle, usrLla, [], [], arrUpa);
linkParam = getLinkParam(scene, wavelen);
steeringInfo = getSceneSteering(scene, wavelen);

[pilotSym, pilotInfo] = genPilotSymbol(numUsr, numSym, 'pn', pwrSource);

% pulse shaping
pulseOpt = struct();
pulseOpt.rolloff = 0.25;
pulseOpt.span = 8;

[pilotWave, waveInfo] = genPilotWaveform(pilotSym, symRate, osf, 'rrc', pulseOpt);

% rx signal generation
modelOpt = struct();
modelOpt.delayMode = 'phaseonly';
modelOpt.carrierPhaseMode = 'none';

[rxSig, sampleCov, cleanSig, noiseSig, meta] = genMultiSatSnapshots( ...
  steeringInfo, pilotWave, linkParam, carrierFreq, waveInfo.sampleRate, ...
  pwrNoise, [], modelOpt);

% s-t music
searchGrid = struct();
searchGrid.range = [0 2*pi; -pi/2 pi/2];
searchGrid.tauRange = [0 0];
searchGrid.fdRange = [-1e4 1e4];

% mle
[estResult, pathGain, noiseVar] = estimatorMlePilotConGrid(scene, ...
  rxSig, pilotWave, carrierFreq, samRate, searchGrid);

%[text] ### Local DoA
doa1_local = scene.localDoa(:,1);
doa2_local = scene.localDoa(:,2);

% design a URA with m elements
arrUpa = createUpa(numElem, elemSpace);
arrUra = ura_2d(numElem, elemSpace);
%%
%[text] ## DOA estimation
doaGrid1 = genDoaGrid("latlon", 2, [50 50], [usrLla(1)-5, usrLla(1)+5; usrLla(2)-5, usrLla(2)+5], 'eci', datevec(utc), scene.satPosEci(:,1), scene.rotMat{1}, E);
doaGrid2 = genDoaGrid("latlon", 2, [50 50], [usrLla(1)-5, usrLla(1)+5; usrLla(2)-5, usrLla(2)+5], 'eci', datevec(utc), scene.satPosEci(:,2), scene.rotMat{2}, E);

spMusic1 = estimatorMusic(scene.array{1}, wavelen, sampleCov{1}, numUsr, doaGrid1, true);
spMusic2 = estimatorMusic(scene.array{2}, wavelen, sampleCov{2}, numUsr, doaGrid2, true);
spMusicJoint = estimatorMusic(scene.array, wavelen, sampleCov, numUsr, {doaGrid1, doaGrid2}, true);

spMvdr1 = estimatorMvdr(scene.array{1}, wavelen, sampleCov{1}, numUsr, doaGrid1, false);
spMvdr2 = estimatorMvdr(scene.array{2}, wavelen, sampleCov{2}, numUsr, doaGrid2, false);
spMvdrJoint = estimatorMvdr(scene.array, wavelen, sampleCov, numUsr, {doaGrid1, doaGrid2}, false);

spMle1 = estimatorMleStoConOpt(scene.array{1}, wavelen, sampleCov{1}, numUsr, doaGrid1);
spMle2 = estimatorMleStoConOpt(scene.array{2}, wavelen, sampleCov{2}, numUsr, doaGrid2);
spMleJoint = estimatorMleStoConOpt(scene.array, wavelen, sampleCov, numUsr, {doaGrid1, doaGrid2});

sp1_music = music_2d(sampleCov{1}, numUsr, arrUra, wavelen, [180 45], 'RefineEstimates', true);
sp2_music = music_2d(sampleCov{2}, numUsr, arrUra, wavelen, [180 45], 'RefineEstimates', true);

spMusic1.latlonEst %[output:45d2bcd1]
spMusic2.latlonEst %[output:3dcd91b1]
spMusicJoint.latlonEst %[output:33498d85]
% doa1_local_est = sp1_music.x_est
% doa2_local_est = sp2_music.x_est
%%
figure(1) %[output:84e83cec]
subplot(131) %[output:84e83cec]
mesh(spMusic1.plot.x, spMusic1.plot.y, spMusic1.plot.z) %[output:84e83cec]
subplot(132) %[output:84e83cec]
mesh(spMusic2.plot.x, spMusic2.plot.y, spMusic2.plot.z) %[output:84e83cec]
subplot(133) %[output:84e83cec]
mesh(spMusicJoint.plot.x, spMusicJoint.plot.y, spMusicJoint.plot.z) %[output:84e83cec]
figure(2) %[output:27b06caa]
subplot(131) %[output:27b06caa]
mesh(spMvdr1.plot.x, spMvdr1.plot.y, spMvdr1.plot.z) %[output:27b06caa]
subplot(132) %[output:27b06caa]
mesh(spMvdr2.plot.x, spMvdr2.plot.y, spMvdr2.plot.z) %[output:27b06caa]
subplot(133) %[output:27b06caa]
mesh(spMvdrJoint.plot.x, spMvdrJoint.plot.y, spMvdrJoint.plot.z) %[output:27b06caa]

